document.addEventListener("DOMContentLoaded",function(){renderAllAsyncapi()});function renderAllAsyncapi(){let e=document.getElementsByClassName("sc-asciinema-container");for(let t=0;t<e.length;t++){let n=e[t].getAttribute("asciinema-options");AsciinemaPlayer.create(e[t].getAttribute("asciinema-url"),e[t],n==""?{}:JSON.parse(n))}}